package nuversestruct

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"

	"haruki-suite/utils/suiterestore"
)

// NewRestorerFromFile builds a suite restorer from a StructTool/custom Avro
// schema generated by unity-msgpack-schema-exporter.
func NewRestorerFromFile(path string) (*suiterestore.Restorer, error) {
	schemaBytes, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read StructTool schema file: %w", err)
	}
	return NewRestorerFromBytes(schemaBytes)
}

// NewRestorerFromBytes builds a suite restorer from StructTool/custom Avro
// schema bytes.
func NewRestorerFromBytes(schemaBytes []byte) (*suiterestore.Restorer, error) {
	definitions, err := GenerateSuiteStructures(schemaBytes)
	if err != nil {
		return nil, fmt.Errorf("generate suite structures from StructTool schema: %w", err)
	}
	restorer, err := suiterestore.NewFromDefinitions(definitions)
	if err != nil {
		return nil, fmt.Errorf("load generated suite structures: %w", err)
	}
	return restorer, nil
}

// IsStructToolSchema reports whether bytes look like a custom Avro record
// schema emitted by unity-msgpack-schema-exporter.
func IsStructToolSchema(data []byte) bool {
	decoder := json.NewDecoder(bytes.NewReader(data))
	decoder.UseNumber()

	var raw map[string]any
	if err := decoder.Decode(&raw); err != nil {
		return false
	}
	if typ, ok := raw["type"].(string); !ok || typ != "record" {
		return false
	}
	fields, ok := raw["fields"].([]any)
	if !ok || len(fields) == 0 {
		return false
	}
	for _, fieldRaw := range fields {
		field, ok := fieldRaw.(map[string]any)
		if !ok {
			continue
		}
		if _, ok := field["msgpack_key"]; ok {
			return true
		}
		if _, ok := field["msgpackKey"]; ok {
			return true
		}
	}
	return false
}
